import type { ComponentProps } from 'react';
import { useRender } from '@base-ui/react/use-render';
import { clsx } from 'clsx';
import styles from './Breadcrumbs.module.css';

function Breadcrumbs({
  className,
  'aria-label': ariaLabel = 'Breadcrumb',
  ...props
}: ComponentProps<'nav'>) {
  return (
    <nav
      data-slot="breadcrumbs-root"
      aria-label={ariaLabel}
      className={clsx(styles.root, className)}
      {...props}
    />
  );
}

function BreadcrumbsList({ className, ...props }: ComponentProps<'ol'>) {
  return <ol data-slot="breadcrumbs-list" className={clsx(styles.list, className)} {...props} />;
}

function BreadcrumbsItem({ className, ...props }: ComponentProps<'li'>) {
  return <li data-slot="breadcrumbs-item" className={clsx(styles.item, className)} {...props} />;
}

function BreadcrumbsLink({ className, render, ...props }: useRender.ComponentProps<'a'>) {
  return useRender({
    defaultTagName: 'a',
    render,
    props: {
      ...props,
      'data-slot': 'breadcrumbs-link',
      className: clsx(styles.link, className),
    },
  });
}

function BreadcrumbsPage({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="breadcrumbs-page"
      aria-current="page"
      className={clsx(styles.page, className)}
      {...props}
    />
  );
}

function BreadcrumbsSeparator({ className, children = '/', ...props }: ComponentProps<'li'>) {
  return (
    <li
      data-slot="breadcrumbs-separator"
      aria-hidden="true"
      className={clsx(styles.separator, className)}
      {...props}
    >
      {children}
    </li>
  );
}

function BreadcrumbsEllipsis({ className, children = '...', ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="breadcrumbs-ellipsis"
      aria-hidden="true"
      className={clsx(styles.ellipsis, className)}
      {...props}
    >
      {children}
    </span>
  );
}

export {
  Breadcrumbs,
  BreadcrumbsList,
  BreadcrumbsItem,
  BreadcrumbsLink,
  BreadcrumbsPage,
  BreadcrumbsSeparator,
  BreadcrumbsEllipsis,
};

@layer ui.components {
  .root {
    max-width: var(--breadcrumbs-max-width, 100%);
    color: var(--breadcrumbs-color, var(--color-muted-foreground));
    font-size: var(--breadcrumbs-font-size, var(--text-sm));
    line-height: var(--breadcrumbs-line-height, var(--line-height-text-sm));
  }

  .list {
    display: flex;
    min-width: 0;
    align-items: center;
    gap: var(--breadcrumbs-gap, var(--spacing-1));
    margin: 0;
    padding: 0;
    list-style: none;
    white-space: nowrap;

    > .item:last-child {
      flex: 1 1 auto;
      max-width: var(--breadcrumbs-item-max-width, 16rem);
    }
  }

  .item {
    display: inline-flex;
    min-width: 0;
    flex: 0 0 auto;
    align-items: center;
  }

  .link,
  .page {
    display: block;
    min-width: 0;
    max-width: 100%;
    padding-inline: var(--breadcrumbs-item-padding-x, 0.25rem);
    white-space: nowrap;
  }

  .link,
  .page,
  .ellipsis {
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .link {
    color: var(--breadcrumbs-link-color, var(--color-muted-foreground));
    text-decoration: var(--breadcrumbs-link-text-decoration, none);
    text-underline-offset: var(--breadcrumbs-link-underline-offset, 0.2em);
    border-radius: var(--breadcrumbs-link-radius, var(--radius-sm));
    outline: none;
    transition: var(--breadcrumbs-link-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        color: var(--breadcrumbs-link-color-hover, var(--color-foreground));
        text-decoration: var(--breadcrumbs-link-text-decoration-hover, none);
      }
    }

    &:focus-visible {
      box-shadow: 0 0 0 var(--breadcrumbs-focus-ring-width, var(--border-width-sm))
        var(--breadcrumbs-focus-ring-color, var(--color-ring));
    }
  }

  .page {
    color: var(--breadcrumbs-page-color, var(--color-foreground));
    font-weight: var(--breadcrumbs-page-font-weight, var(--weight-medium));
  }

  .separator {
    display: inline-flex;
    align-items: center;
    color: var(--breadcrumbs-separator-color, var(--color-muted-foreground));
    font-size: var(--breadcrumbs-separator-font-size, 0.875em);
    line-height: 1;
    user-select: none;
  }

  .ellipsis {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: var(--breadcrumbs-ellipsis-size, 1rem);
    min-height: var(--breadcrumbs-ellipsis-size, 1rem);
    padding-inline: var(--breadcrumbs-item-padding-x, 0.25rem);
    color: var(--breadcrumbs-ellipsis-color, var(--color-muted-foreground));
    border-radius: var(--breadcrumbs-ellipsis-radius, var(--radius-sm));
    transition: background-color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--color-accent);
      }
    }
  }
}

export {
  Breadcrumbs,
  BreadcrumbsList,
  BreadcrumbsItem,
  BreadcrumbsLink,
  BreadcrumbsPage,
  BreadcrumbsSeparator,
  BreadcrumbsEllipsis,
} from './Breadcrumbs';
